<?php $page_title='Thanh toán';require __DIR__.'/_layout_start.php';$pdo=db_connect();if(is_post()){$id=(int)($_POST['id']??0);if($id)$pdo->prepare("UPDATE phuong_thuc_thanh_toan SET ten_phuong_thuc=:n,mo_ta=:m,trang_thai=:t WHERE id_phuong_thuc=:id")->execute([':n'=>$_POST['name'],':m'=>$_POST['mo_ta'],':t'=>$_POST['trang_thai'],':id'=>$id]);else $pdo->prepare("INSERT INTO phuong_thuc_thanh_toan(ten_phuong_thuc,mo_ta,trang_thai) VALUES(:n,:m,:t)")->execute([':n'=>$_POST['name'],':m'=>$_POST['mo_ta'],':t'=>$_POST['trang_thai']]);redirect('admin/payment_methods.php');}$rows=$pdo->query("SELECT * FROM phuong_thuc_thanh_toan")->fetchAll();?><h1>Phương thức thanh toán</h1><form method="post" class="bg-white p-4 rounded-4 mb-4"><input name="name" class="form-control mb-2" placeholder="Tên"><textarea name="mo_ta" class="form-control mb-2"></textarea><select name="trang_thai" class="form-select mb-2"><option value="hien">Hiện</option><option value="an">Ẩn</option></select><button class="btn btn-primary">Thêm</button></form><div class="bg-white p-4 rounded-4"><table class="table"><?php foreach($rows as $r):?><tr><td><?=h($r['ten_phuong_thuc'])?></td><td><?=h($r['trang_thai'])?></td></tr><?php endforeach;?></table></div><?php require __DIR__.'/_layout_end.php';?>
